const dbRecord = $('Loop: oferta por oferta').item.json;
const dbId = String(dbRecord.id || '');
const dbUrl = String(dbRecord.url || '');

// La respuesta HTML viene como string en $input.item.json.data o directamente
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut
  : (httpOut.data || httpOut.body || httpOut.html || '');

console.log('[flexicar-enrich] id=' + dbId + ' url=' + dbUrl + ' html_len=' + String(html).length);

if (!dbId) {
  await new Promise(r => setTimeout(r, 800));
  return [{ json: { id: null, hasUpdates: false, updateSql: null } }];
}

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}

function normalizeBody(raw) {
  const s = String(raw || '').toLowerCase();
  if (!s) return '';
  if (s.indexOf('suv') !== -1 || s.indexOf('4x4') !== -1 || s.indexOf('todoterreno') !== -1 || s.indexOf('todo') !== -1) return 'SUV';
  if (s.indexOf('pick') !== -1) return 'Pick Up';
  if (s.indexOf('furgon') !== -1 || s.indexOf('van') !== -1 || s.indexOf('comercial') !== -1) return 'Furgoneta';
  if (s.indexOf('familiar') !== -1 || s.indexOf('estate') !== -1 || s.indexOf('combi') !== -1) return 'Familiar';
  if (s.indexOf('monovolumen') !== -1 || s.indexOf('mpv') !== -1) return 'Monovolumen';
  if (s.indexOf('coupe') !== -1 || s.indexOf('coupé') !== -1 || s.indexOf('coup') !== -1) return 'Coupé';
  if (s.indexOf('cabrio') !== -1 || s.indexOf('convert') !== -1 || s.indexOf('descapotable') !== -1) return 'Cabrio';
  if (s.indexOf('pequeñ') !== -1 || s.indexOf('pequen') !== -1 || s.indexOf('compact') !== -1 || s.indexOf('ciudad') !== -1 || s.indexOf('utilitario') !== -1) return 'Compacto';
  if (s.indexOf('berlina') !== -1 || s.indexOf('sedan') !== -1 || s.indexOf('turismo') !== -1 || s.indexOf('hatchback') !== -1) return 'Berlina';
  return raw || '';
}

function normalizeTraction(raw) {
  const s = String(raw || '').toLowerCase();
  if (s.indexOf('total') !== -1 || s.indexOf('integral') !== -1 || s.indexOf('4x4') !== -1 || s.indexOf('awd') !== -1 || s.indexOf('4wd') !== -1) return '4x4';
  if (s.indexOf('tras') !== -1 || s.indexOf('rear') !== -1) return 'Trasera';
  if (s.indexOf('del') !== -1 || s.indexOf('front') !== -1) return 'Delantera';
  return '';
}

// ── Extraer __NEXT_DATA__ ──────────────────────────────────────────────────
let vehicle = null;
const htmlStr = String(html);

try {
  const ndMatch = htmlStr.match(/<script id="__NEXT_DATA__" type="application\/json">([\s\S]*?)<\/script>/);
  if (ndMatch) {
    const nd = JSON.parse(ndMatch[1]);
    console.log('[flexicar-enrich] __NEXT_DATA__ keys=' + Object.keys(nd).join(','));
    const pp = (nd.props || {}).pageProps || {};
    vehicle = pp.vehicle || pp.car || pp.data || pp.offer
      || ((nd.props || {}).initialState || {}).vehicle
      || null;
    if (!vehicle && pp.dehydratedState) {
      const queries = ((pp.dehydratedState || {}).queries || []);
      for (const q of queries) {
        const d = (q.state || {}).data;
        if (d && (d.color !== undefined || d.doors !== undefined || d.id !== undefined)) {
          vehicle = d; break;
        }
      }
    }
    if (vehicle) {
      console.log('[flexicar-enrich] vehicle keys=' + Object.keys(vehicle).join(','));
    } else {
      console.log('[flexicar-enrich] vehicle not found in __NEXT_DATA__, pp keys=' + Object.keys(pp).join(','));
    }
  } else {
    console.log('[flexicar-enrich] no __NEXT_DATA__ found');
  }
} catch(e) {
  console.log('[flexicar-enrich] parse error: ' + e.message);
}

// ── Extraer campos ─────────────────────────────────────────────────────────
let colorVal = '', doorsVal = 0, seatsVal = 0, hpVal = 0;
let cylCC = 0, consumVal = 0, bodyVal = '', tractionVal = '', co2Val = '';
let imgUrls = [];

if (vehicle) {
  colorVal   = vehicle.color || vehicle.colorName || vehicle.colour || vehicle.colorExterior || '';
  doorsVal   = vehicle.doors || vehicle.numDoors || vehicle.numberOfDoors || vehicle.puertas || 0;
  seatsVal   = vehicle.seats || vehicle.numSeats || vehicle.numberOfSeats || vehicle.plazas || 0;
  hpVal      = vehicle.hp || vehicle.power || vehicle.cv || vehicle.potencia || vehicle.horsePower || 0;
  const cylRaw = vehicle.cylinder || vehicle.displacement || vehicle.cc || vehicle.engineDisplacement || vehicle.cilindrada || 0;
  cylCC      = cylRaw > 100 ? Math.round(cylRaw) : Math.round(cylRaw * 1000);
  consumVal  = vehicle.mixedConsumption || vehicle.consumption || vehicle.fuelConsumption || vehicle.consumo || 0;
  bodyVal    = vehicle.body || vehicle.bodyType || vehicle.carType || vehicle.carroceria || vehicle.bodyWork || '';
  tractionVal= vehicle.traction || vehicle.traccion || vehicle.driveType || vehicle.tractionType || '';
  co2Val     = String(vehicle.co2 || vehicle.emissions || vehicle.co2Emissions || '');

  const imgsRaw = vehicle.images || vehicle.photos || vehicle.gallery || [];
  if (Array.isArray(imgsRaw) && imgsRaw.length > 0) {
    if (typeof imgsRaw[0] === 'string') {
      imgUrls = imgsRaw.filter(Boolean).slice(0, 20);
    } else {
      imgUrls = imgsRaw.map(function(i) { return i.image || i.url || i.src || ''; }).filter(Boolean).slice(0, 20);
    }
  }
  // Descartar imágenes genéricas (banners de red de concesionarios, no del coche)
  imgUrls = imgUrls.filter(function(u){ return u && u.indexOf('/generic/') === -1 && u.indexOf('dealer_network') === -1; });

  const dataSheetArr = vehicle.dataSheet || vehicle.specs || vehicle.characteristics || [];
  if (!tractionVal && Array.isArray(dataSheetArr)) {
    const ds = dataSheetArr.join(' ').toLowerCase();
    tractionVal = ds.indexOf('total') !== -1 || ds.indexOf('integral') !== -1 || ds.indexOf('4x4') !== -1 ? '4x4'
      : ds.indexOf('trasera') !== -1 ? 'Trasera'
      : ds.indexOf('delantera') !== -1 ? 'Delantera' : '';
  }
  if (!co2Val && Array.isArray(dataSheetArr)) {
    const dsText = dataSheetArr.join(' ');
    const idx = dsText.toLowerCase().indexOf('emisiones wltp ice');
    if (idx !== -1) {
      const m = dsText.slice(idx + 18, idx + 60).match(/(\d+)/);
      if (m) co2Val = m[1];
    }
  }
} else {
  const mColor = htmlStr.match(/"color"\s*:\s*"([^"]+)"/i) || htmlStr.match(/color[^>]*>([A-ZÁÉÍÓÚÜÑ][a-záéíóúüñ]+)</);
  if (mColor) colorVal = mColor[1];

  const mDoors = htmlStr.match(/"(?:doors|numDoors|puertas)"\s*:\s*(\d+)/);
  if (mDoors) doorsVal = parseInt(mDoors[1], 10);

  const mSeats = htmlStr.match(/"(?:seats|numSeats|plazas)"\s*:\s*(\d+)/);
  if (mSeats) seatsVal = parseInt(mSeats[1], 10);

  const mHp = htmlStr.match(/"(?:hp|power|cv|potencia)"\s*:\s*(\d+)/);
  if (mHp) hpVal = parseInt(mHp[1], 10);

  const mCyl = htmlStr.match(/"(?:cylinder|displacement|cc)"\s*:\s*([\d.]+)/);
  if (mCyl) { const v = parseFloat(mCyl[1]); cylCC = v > 100 ? Math.round(v) : Math.round(v * 1000); }

  const mCons = htmlStr.match(/"(?:mixedConsumption|consumption|consumo)"\s*:\s*([\d.]+)/);
  if (mCons) consumVal = parseFloat(mCons[1]);

  const mBody = htmlStr.match(/"(?:body|bodyType|carType|carroceria)"\s*:\s*"([^"]+)"/);
  if (mBody) bodyVal = mBody[1];

  const mTrac = htmlStr.match(/"(?:traction|traccion|driveType)"\s*:\s*"([^"]+)"/);
  if (mTrac) tractionVal = mTrac[1];

  const mCo2 = htmlStr.match(/"(?:co2|emissions|co2Emissions)"\s*:\s*"?([\d]+)"?/);
  if (mCo2) co2Val = mCo2[1];

  console.log('[flexicar-enrich] regex fallback: color=' + colorVal + ' doors=' + doorsVal + ' seats=' + seatsVal);
}

// ── Construir SQL ──────────────────────────────────────────────────────────
const sets = [];

if (colorVal)                 sets.push('color = COALESCE(NULLIF(color,\'\'), ' + esc(colorVal) + ')');
if (Number(doorsVal) > 0)     sets.push('doors = COALESCE(NULLIF(doors,0), ' + Number(doorsVal) + ')');
if (Number(seatsVal) > 0)     sets.push('seats = COALESCE(NULLIF(seats,0), ' + Number(seatsVal) + ')');
if (Number(hpVal) > 0)        sets.push('power_cv = COALESCE(NULLIF(power_cv,0), ' + Number(hpVal) + ')');
if (cylCC > 0)                sets.push('displacement = COALESCE(NULLIF(displacement,\'\'), \'' + cylCC + '\')');
if (Number(consumVal) > 0)    sets.push('consumption = COALESCE(NULLIF(consumption,0), ' + Number(consumVal) + ')');
if (bodyVal)                  sets.push('body_type = COALESCE(NULLIF(body_type,\'\'), ' + esc(normalizeBody(bodyVal)) + ')');
if (imgUrls.length > 0) {
  sets.push('image_url = COALESCE(NULLIF(image_url,\'\'), ' + esc(imgUrls[0]) + ')');
  sets.push('images = COALESCE(NULLIF(images,\'\'), ' + esc(JSON.stringify(imgUrls)) + ')');
}
const trNorm = normalizeTraction(tractionVal);
if (trNorm)                   sets.push('traction = COALESCE(NULLIF(traction,\'\'), ' + esc(trNorm) + ')');
if (co2Val && /^\d+$/.test(co2Val.trim())) sets.push('co2 = COALESCE(NULLIF(co2,\'\'), ' + esc(co2Val.trim()) + ')');

sets.push('enrich_tried_at = NOW()');

const updateSql = 'UPDATE moveadvisor_market_offers SET ' + sets.join(', ') + ', updated_at = NOW() WHERE id = \'' + dbId.replace(/'/g, "''") + "'";

console.log('[flexicar-enrich] sets=' + sets.length + ' sql=' + updateSql.slice(0, 400));

await new Promise(r => setTimeout(r, 800));

return [{ json: { id: dbId, hasUpdates: true, updateSql: updateSql } }];
